class Solution:
    def paintWalls(self, cost, time):
        n = len(cost)
        best = None
        for mask in range(1 << n):
            total_time = 0
            total_cost = 0
            chosen = 0
            for i in range(n):
                if mask & (1 << i):
                    total_time += time[i]
                    total_cost += cost[i]
                    chosen += 1
            if total_time >= n - chosen:
                if best is None or total_cost < best:
                    best = total_cost
        return best

