class Solution:
    def paintWalls(self, cost, time):
        n = len(cost)
        INF = float('inf')
        dp = [0] + [INF] * n
        for i in range(n):
            c, t = cost[i], time[i]
            for j in range(n, -1, -1):
                if dp[j] == INF:
                    continue
                nj = j + t + 1
                if nj > n:
                    nj = n
                if dp[j] + c < dp[nj]:
                    dp[nj] = dp[j] + c
        return dp[n]

