var paintWalls = function(cost, time) {
    const n = cost.length;
    const INF = Infinity;
    const dp = new Array(n + 1).fill(INF);
    dp[0] = 0;
    for (let i = 0; i < n; i++) {
        const c = cost[i], t = time[i];
        for (let j = n; j >= 0; j--) {
            if (dp[j] === INF) continue;
            const nj = Math.min(n, j + t + 1);
            if (dp[j] + c < dp[nj]) dp[nj] = dp[j] + c;
        }
    }
    return dp[n];
};
